iers_a = getIers()


class TransitInfo( dict ):
 def __init__(self):
  dict.__init__(self)
  self["begin"]=0
  self["end"]=0
  self["middle"]=0

 def __repr__(self):
  _ret = ""
  #_ret += "| {:20s} ".format( (self["middle"].ut1.isot).replace("T"," ") )
  #_ret += "| {:20s} ".format( (self["middle_utc"].ut1.isot).replace("T"," ") )
#  _ret += "| {:20s} ".format( (self["begin"].utc.isot).replace("T"," ") )
  _ret += "| {:20s} ".format( (self["middle"].utc.isot).replace("T"," ") )
  _ret += "| {:20s} ".format( (self["middle_utc"].utc.isot).replace("T"," ") )
  return _ret

 def update(self, observatory):
  for keyword in self.keys():
   self[keyword] = Time( self[keyword], format="jd", scale='utc', precision=6 )
   self[keyword] = Time( self[keyword].utc, format="iso", scale='utc', precision=6, out_subfmt="date_hm" )
   #self[keyword].delta_ut1_utc = self[keyword].get_delta_ut1_utc(iers_a)
  self["middle_utc"] = self["middle"] + observatory["UtcOffset"]
  #self["middle_utc"].delta_ut1_utc = self["middle_utc"].get_delta_ut1_utc(iers_a)

 def isNight(self, solarTwilight):
  expr1 = solarTwilight['Nautical0'].jd < self["middle"].jd
  expr2 = self["middle"].jd < solarTwilight['Nautical1'].jd 
  self["isNight"] = bool(expr1 * expr2)

 def calculateAltAz(self, observatory, skyCoord):
  colors = ["black", "blue", "yellow", "magenta", "red"] + [  "red" for i in range(10) ]
  for keyword in [ "begin", "middle", "end" ]:
   AltAzFrameTransit = AltAz(obstime=self[keyword], location=observatory["EarthLocation"])
   objTransit = skyCoord.transform_to(AltAzFrameTransit)
   self[ "{}_z".format( keyword ) ] = round( 90 - objTransit.alt.to(u.deg).value, 1 )
   self[ "{}_az".format( keyword )  ] = round( objTransit.az.to(u.deg).value, 1 )
   i = int(self[ "{}_z".format( keyword ) ]/20)
   self[ "{}_color".format( keyword )  ] = colors[i]

#  if (self["begin_z"]>90.0) and (self["end_z"]>90.0) and (self["middle_z"]>90.0):
