class ListObjectOfInterest( list ):
 def __init__(self):
  list.__init__(self)

 def parseTxtFile(self, FileName="obj.dat"):
  Strs = open(FileName).readlines()
  for Str in Strs:
   if Str.find("#")==-1:
    obj = {}
    a = Str.split()
    if len(a)>=8:
     obj["name"], obj["transittime"], obj["period"], obj["RA"], obj["DEC"], obj["mag"], obj["trans_depht"], obj["duraction"] = a[0:8]
     objectOfInterest = ObjectOfInterest()
     objectOfInterest.add( obj )
     self.append( objectOfInterest )

 def parseCsvFile(self, FileName="obj.csv"):
  Strs = open(FileName).readlines()
  for Str in Strs:
   if Str.find("#")==-1:
    obj = {}
    a = Str.split(",")
    if len(a)>=8:
     obj["name"], obj["transittime"], obj["period"], obj["RA"], obj["DEC"], obj["mag"], obj["trans_depht"], obj["duraction"] = a[0:8]
     objectOfInterest = ObjectOfInterest()
     objectOfInterest.add( obj )
     self.append( objectOfInterest )

#  print self
 def sortOrder(self, objectOfInterest):
  if len(objectOfInterest["transitsList"])==0:
   objectOfInterest["transitsList"].append({"middle":Time("1970-01-01"), "isNight":False})
  return objectOfInterest["transitsList"][0]["middle"]

 def sortObject(self):
  self.sort(key=self.sortOrder)

 def parseXmlFile(self, FileName="test.xml"):
  objectOfInterest = ObjectOfInterest()
  objectOfInterest.add( FileName )
  self.append( objectOfInterest )

 def parseXmlRegExp(self, FileNameList=[]):
  for FileName in FileNameList:
   print( FileName )
   objectOfInterest = ObjectOfInterest()
   objectOfInterest.add( FileName )
   self.append( objectOfInterest )

 def calculateTransits(self, solarTwilight, observatory ):
  [ item.calculateTransitTime( solarTwilight, observatory )  for item in self ]

class ObjectOfInterest( dict ):
 def __init__(self):
  dict.__init__(self)

 def __repr__(self):
  _ret = ""
  _ret += "|{:20s}".format( self["name"] )
  _ret += "| {:13s}".format( self["RA"] )
  _ret += "| {:13s}".format( self["DEC"] )
  _ret += "| {:6.3f}mag".format( self["mag"] )
  _ret += "| {:6.3f}mag".format( self["trans_depht"] )
  _ret += "|{:10.6f}day".format( self["period"] )
  _ret += "|{:7.3f}hour".format( self["duraction"] )
  return _ret

 def add(self, source):
  if isinstance( source, dict ):
   self.addFromDict(source)
  elif isinstance( source, str ) and os.path.exists( source ):
   d = ExoplanetCatalogue( source )
   self.addFromDict(d)

 def addFromDict(self, source):
  for keyword in source.keys():
   self[keyword] = source[keyword]
  self.correctValues()

 def correctValues(self):
   try:
    self["RA"] = float(self["RA"])
    self["DEC"] = float(self["DEC"])
    objSkyCoord = "{RA} {DEC}".format( **self )
    self["SkyCoord"] = SkyCoord( objSkyCoord , frame=FK5, unit=(u.deg,u.deg), obstime="J2000.0")
   except:
    objSkyCoord = "{RA} {DEC}".format( **self )
    self["SkyCoord"] = SkyCoord( objSkyCoord , frame=FK5, unit=(u.hourangle,u.deg), obstime="J2000.0")
   self["RA"],self["DEC"] =  self["SkyCoord"].to_string("hmsdms").split()

   for keyword in [ "transittime", "duraction", "period", "mag", "trans_depht" ]:
    if keyword in self:
     self[keyword] = self.toFloat( self[keyword] )
    else:
     print( keyword )
     self[keyword] = np.nan

   if self["trans_depht"] > 1:
    self["trans_depht"] = self.ppm2mag( self["trans_depht"] )

 def ppm2mag(self, ppm):
  return -2.5 * np.log10(1-ppm*1e-6)

 def toFloat(self, value):
  try:
   return float( value )
  except:
   print( value )
   np.nan

 def calculateTransitTime(self, solarTwilight, observatory ):
  self["transitsList"] = []
#  if True:
  try:
   iBegin = int( ( solarTwilight["dateOfInterest"].jd - self["transittime"])  / self["period"] ) - 1
   iEnd = int( ( (solarTwilight["dateOfInterest"] + 24*u.hour).jd - self["transittime"])  / self["period"] ) + 1
   for iTime in range(iBegin, iEnd+1, 1):
    transitInfo = TransitInfo()
    transitInfo["middle"] = self["transittime"] + self["period"] * iTime
    transitInfo["begin"] = transitInfo["middle"] - (self["duraction"] * u.hour).to(u.day).value / 2.0
    transitInfo["end"]   = transitInfo["middle"] + (self["duraction"] * u.hour).to(u.day).value / 2.0
    transitInfo.update(observatory)
    transitInfo.isNight(solarTwilight)
    '''
    if transitInfo["isNight"]:
     transitInfo.calculateAltAz(observatory, self["SkyCoord"])
    self["transitsList"].append( transitInfo )
    '''
    if transitInfo["isNight"]:
     transitInfo.calculateAltAz(observatory, self["SkyCoord"])
     self["transitsList"].append( transitInfo )
  except ValueError:
   print( "Warning" )


start_date=datetime.datetime(2026,3,1)
end_date=datetime.datetime(2026,3,15)

def daterange(start_date, end_date):
 for n in range(int ((end_date - start_date).days)):
  yield start_date + datetime.timedelta(n)


